import{_ as a,o as r,c as n,a2 as s}from"./chunks/framework.D2pTuMig.js";const p=JSON.parse('{"title":"Gestion des Campagnes","description":"","frontmatter":{"title":"Gestion des Campagnes"},"headers":[],"relativePath":"docs/fr/faq/campaign-management.md","filePath":"docs/fr/faq/campaign-management.md"}'),t={name:"docs/fr/faq/campaign-management.md"};function i(o,e,u,l,d,c){return r(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="gestion-des-campagnes" tabindex="-1">Gestion des Campagnes <a class="header-anchor" href="#gestion-des-campagnes" aria-label="Permalink to &quot;Gestion des Campagnes&quot;">​</a></h1><h2 id="quel-est-le-delai-de-reponse-attendu" tabindex="-1">Quel est le délai de réponse attendu ? <a class="header-anchor" href="#quel-est-le-delai-de-reponse-attendu" aria-label="Permalink to &quot;Quel est le délai de réponse attendu ?&quot;">​</a></h2><p>Vous devez répondre sous <strong>48 heures ouvrées</strong>. La réactivité est la clé pour remporter les campagnes face aux autres retailers. Passé ce délai, getinside se réserve le droit de refuser la campagne en votre nom et d&#39;appliquer une pénalité correspondante aux frais de plateforme prévus.</p><h2 id="puis-je-annuler-une-campagne-deja-acceptee" tabindex="-1">Puis-je annuler une campagne déjà acceptée ? <a class="header-anchor" href="#puis-je-annuler-une-campagne-deja-acceptee" aria-label="Permalink to &quot;Puis-je annuler une campagne déjà acceptée ?&quot;">​</a></h2><p>L&#39;annulation est fortement déconseillée. Sauf force majeure, des pénalités s&#39;appliquent :</p><ul><li>Pénalité forfaitaire de <strong>250€</strong></li><li>+ Remboursement des frais de plateforme perdus</li><li>+ Remboursement des frais de production (si imprimé) et de studio engagés</li></ul><h2 id="puis-je-refuser-d-inserer-un-flyer-recu" tabindex="-1">Puis-je refuser d&#39;insérer un flyer reçu ? <a class="header-anchor" href="#puis-je-refuser-d-inserer-un-flyer-recu" aria-label="Permalink to &quot;Puis-je refuser d&#39;insérer un flyer reçu ?&quot;">​</a></h2><p>Oui. Vérifiez la marchandise à réception. Si les supports sont endommagés ou non conformes au BAT validé (ex : marque concurrente non signalée), contactez immédiatement le support (<code>studio@getinside.fr</code>) et suspendez l&#39;insertion.</p><h2 id="la-campagne-demarre-en-retard-—-que-faire" tabindex="-1">La campagne démarre en retard — que faire ? <a class="header-anchor" href="#la-campagne-demarre-en-retard-—-que-faire" aria-label="Permalink to &quot;La campagne démarre en retard — que faire ?&quot;">​</a></h2><p>Si vous n&#39;avez rien distribué sur une semaine prévue :</p><ol><li>Saisissez <strong>&quot;0&quot;</strong> dans le reporting de la semaine.</li><li>Prévenez l&#39;annonceur via la messagerie.</li></ol><p>La plateforme prolongera automatiquement la campagne en fin de période pour atteindre le volume cible.</p><h2 id="comment-ajouter-un-nouveau-type-d-offre" tabindex="-1">Comment ajouter un nouveau type d&#39;offre ? <a class="header-anchor" href="#comment-ajouter-un-nouveau-type-d-offre" aria-label="Permalink to &quot;Comment ajouter un nouveau type d&#39;offre ?&quot;">​</a></h2><p>Allez sur la fiche de l&#39;audience concernée et ajoutez un type de campagne. Pour une offre sur-mesure (hors catalogue standard), sélectionnez <strong>&quot;Autre type de campagne&quot;</strong> — l&#39;équipe getinside validera la faisabilité avec vous.</p><h2 id="ou-voir-l-historique-de-mes-campagnes" tabindex="-1">Où voir l&#39;historique de mes campagnes ? <a class="header-anchor" href="#ou-voir-l-historique-de-mes-campagnes" aria-label="Permalink to &quot;Où voir l&#39;historique de mes campagnes ?&quot;">​</a></h2><ul><li><strong>Campagnes reçues (Retailer) :</strong> Monétisation → Gestionnaire de campagne (filtrez par statut : Accepté, Refusé…)</li><li><strong>Vos propres campagnes (Annonceur) :</strong> Campagnes → Toutes les campagnes</li></ul><h2 id="comment-suivre-les-performances-de-ma-campagne" tabindex="-1">Comment suivre les performances de ma campagne ? <a class="header-anchor" href="#comment-suivre-les-performances-de-ma-campagne" aria-label="Permalink to &quot;Comment suivre les performances de ma campagne ?&quot;">​</a></h2><p>Vous disposez d&#39;un double suivi sur votre tableau de bord getinside :</p><ol><li><strong>Performance (ROI) :</strong> Scans de vos QR codes en temps réel.</li><li><strong>Distribution :</strong> Volumes de flyers insérés mis à jour chaque début de semaine par le distributeur.</li></ol><h2 id="un-distributeur-refuse-mon-visuel-—-que-faire" tabindex="-1">Un distributeur refuse mon visuel — que faire ? <a class="header-anchor" href="#un-distributeur-refuse-mon-visuel-—-que-faire" aria-label="Permalink to &quot;Un distributeur refuse mon visuel — que faire ?&quot;">​</a></h2><p>Le distributeur a un <strong>droit de veto sur la marque</strong> (concurrent direct, catégorie éthiquement incompatible) — mais pas sur la direction artistique.</p><p>Si votre visuel respecte les spécifications techniques (fond perdu 2mm, zone tranquille 3mm, résolution 300 DPI, mentions légales présentes), il est conforme. Le distributeur ne peut pas le rejeter pour des raisons subjectives de goût ou de style.</p><p><strong>Marche à suivre :</strong></p><ol><li>Vérifiez que votre fichier respecte bien les <a href="/handbook/docs/fr/advertisers/sponsored-mail/design-guide/print-specs.html">spécifications d&#39;impression</a>.</li><li>Si tout est conforme, transmettez votre BAT à <a href="mailto:studio@getinside.fr" target="_blank" rel="noreferrer">studio@getinside.fr</a> pour validation officielle.</li><li>La validation getinside prime sur l&#39;appréciation subjective du distributeur.</li></ol><h2 id="un-annonceur-me-demande-les-adresses-de-mes-clients-—-puis-je-les-donner" tabindex="-1">Un annonceur me demande les adresses de mes clients — puis-je les donner ? <a class="header-anchor" href="#un-annonceur-me-demande-les-adresses-de-mes-clients-—-puis-je-les-donner" aria-label="Permalink to &quot;Un annonceur me demande les adresses de mes clients — puis-je les donner ?&quot;">​</a></h2><p><strong>Non, en aucun cas.</strong> Cette demande est contraire au RGPD et à nos CGU.</p><p>Vos données clients sont un actif <strong>First Party</strong> qui vous appartient exclusivement. getinside opère comme <strong>Tiers de Confiance</strong> : l&#39;annonceur accède à votre audience sans jamais recevoir le fichier. Aucun transfert de base n&#39;est autorisé sans opt-in spécifique de chaque client.</p><p>En cas de demande insistante, contactez <a href="mailto:support@getinside.fr" target="_blank" rel="noreferrer">support@getinside.fr</a> — notre équipe prend en charge la réponse légale.</p>',28)])])}const f=a(t,[["render",i]]);export{p as __pageData,f as default};
